// Auto-generiert aus Karteikarten_Risikomanagement_Mattejat.md — nicht von Hand bearbeiten.
// Fach: Risikomanagement & Rückversicherung (Mattejat) · Tags: klausur 🎯, rechnen 🧮, achtung ⚠️
const RISK_CARDS = [
  {"id": 1, "cat": "A", "label": "Grundlagen", "q": "Wie wird „Risiko\" definiert?", "a": "Als **Informationsdefizit über die finale Bestimmtheit** – also die Ungewissheit über das Erreichen der gesteckten/geplanten Ziele.", "tags": []},
  {"id": 2, "cat": "A", "label": "Grundlagen", "q": "Wie lautet die Risiko-Formel (Produktdarstellung)?", "a": "**Risk = Value × Vulnerability × Hazard** (Wert × Verwundbarkeit × Gefahr). Fällt einer der Faktoren auf 0, gibt es kein Risiko.", "tags": []},
  {"id": 3, "cat": "A", "label": "Grundlagen", "q": "Kann Risiko auch positiv sein? Erkläre Risiko i.w.S. vs. i.e.S.", "a": "Ja – wer Risiken eingeht, ermöglicht Innovation. Grafisch: Von der erwarteten Entwicklung kann die Realität nach oben (**Chance**) oder unten (**Risiko i.e.S.**) abweichen. Beides zusammen = **Risiko i.w.S.** (Abweichung in beide Richtungen).", "tags": []},
  {"id": 4, "cat": "A", "label": "Grundlagen", "q": "Was muss in jedem Rückversicherungsvertrag zwingend enthalten sein?", "a": "Ein gewisser **Risikotransfer** – sonst ist es keine (Rück-)Versicherung.", "tags": []},
  {"id": 5, "cat": "A", "label": "Grundlagen", "q": "Was ist die ISO 31000?", "a": "Ein **branchenübergreifender Standard** für Risikomanagement (für alle Arten von Risiken anwendbar). Enthält Richtlinien, Grundsätze, Rahmenbedingungen und einen RM-Prozess. **ABER:** nur ein Framework – jedes Unternehmen muss es individuell anpassen.", "tags": []},
  {"id": 6, "cat": "A", "label": "Grundlagen", "q": "Nenne die 3 Hauptprinzipien der ISO 31000.", "a": "1) RM als **Führungsaufgabe**, 2) RM als **Top-Down-Ansatz**, 3) RM als **allgemeiner, sektorübergreifender Ansatz**.", "tags": []},
  {"id": 7, "cat": "A", "label": "Grundlagen", "q": "KonTraG – wofür steht es und was ist der Kern?", "a": "**Gesetz zur Kontrolle und Transparenz im Unternehmensbereich.** Kern: **zwingende Einführung eines Risikofrüherkennungssystems.** Ziel: Verbesserung der Corporate Governance.", "tags": []},
  {"id": 8, "cat": "A", "label": "Grundlagen", "q": "Welche 3 wesentlichen Prozesse müssen Unternehmen laut KonTraG umsetzen?", "a": "1) **Überwachungssystem zur Früherkennung** errichten (Identifikation & Analyse), 2) **angemessene Kommunikationsstruktur** schaffen, 3) **rechtzeitige Einleitung geeigneter Gegenmaßnahmen.**", "tags": []},
  {"id": 9, "cat": "A", "label": "Grundlagen", "q": "Welche weiteren Inhalte legt das KonTraG fest (über die 3 Prozesse hinaus)?", "a": "Verschärfung von RM & Überwachungssystem (Identifikation, Analyse/Bewertung, Steuerung, Überwachung); **erhöhte Anforderungen an die Abschlussprüfung**; Lagebericht mit Prognosecharakter; Wirtschaftsprüfer zu verstärkter Risikobeurteilung verpflichtet; besseres Risikobewusstsein der Geschäftsführung; **verschärfte Haftung** für Aufsichtsrat, Vorstand, Geschäftsführer und Abschlussprüfer.", "tags": []},
  {"id": 10, "cat": "A", "label": "Grundlagen", "q": "Wer ist vom KonTraG hauptsächlich betroffen?", "a": "Hauptsächlich **(große) AGs** – nicht alle Unternehmen sind zu Risikomanagement verpflichtet.", "tags": []},
  {"id": 11, "cat": "A", "label": "Grundlagen", "q": "Was bedeutet Corporate Governance?", "a": "**Gute Unternehmensführung** – Leitbild des „ehrbaren Kaufmanns\".", "tags": []},
  {"id": 12, "cat": "B", "label": "Risikoarten", "q": "Nenne die Kategorien von Risikoarten (Überblick).", "a": "1) Finanzielle, 2) betriebliche/technische, 3) rechtliche, 4) Ressourcen-, 5) strategische, 6) technologische, 7) zeitliche, 8) Stakeholder-, 9) Umwelt- & soziale (inkl. Naturkatastrophen), 10) politische & wirtschaftliche Risiken.", "tags": ["klausur"]},
  {"id": 13, "cat": "B", "label": "Risikoarten", "q": "Welche finanziellen Risiken gibt es?", "a": "Markt(preis)risiko, Bonitäts-/Ausfall-/Kreditrisiko, **Liquiditätsrisiko**, Inflationsrisiko, Währungs(kurs)risiko, Zinsrisiko.", "tags": ["klausur"]},
  {"id": 14, "cat": "B", "label": "Risikoarten", "q": "Erkläre das Liquiditätsrisiko mit Beispiel.", "a": "Auf dem Papier genug Vermögen, aber **nicht flüssig**: z.B. viele Immobilien, 0 € Cash – kurzfristige Zahlungen können nicht bedient werden (großes Risiko für Banken).", "tags": ["klausur"]},
  {"id": 15, "cat": "B", "label": "Risikoarten", "q": "Erkläre das Währungs(kurs)risiko mit Beispiel.", "a": "Investition in fremder Währung (z.B. in €): Durch Wechselkursschwankungen entsteht Gewinn oder Verlust unabhängig von der eigentlichen Anlage.", "tags": ["klausur"]},
  {"id": 16, "cat": "B", "label": "Risikoarten", "q": "Betriebliche/technische Risiken – nenne 2 mit Beispiel.", "a": "**Produktionsrisiko:** Risiken aus der Herstellung von Produkten (z.B. Maschinenausfälle). **Lieferkettenrisiko:** Störungen in der Lieferkette (z.B. Lieferausfall bei Single-Sourcing).", "tags": ["klausur"]},
  {"id": 17, "cat": "B", "label": "Risikoarten", "q": "Rechtliche Risiken – welche gibt es und wie kann man sie beeinflussen?", "a": "**Haftungsrisiken** (aus rechtlichen Ansprüchen/Klagen → Unternehmen muss Strafe zahlen) und **Compliance-Risiken** (Nichteinhaltung von Gesetzen & Vorschriften). Vermeidung u.a. durch **Lobbyismus**.", "tags": ["klausur"]},
  {"id": 18, "cat": "B", "label": "Risikoarten", "q": "Welche Ressourcenrisiken gibt es?", "a": "**Rohstoffe** und **(qualifiziertes) Personal**.", "tags": ["klausur"]},
  {"id": 19, "cat": "B", "label": "Risikoarten", "q": "Strategische Risiken – nenne 2 mit Beispiel.", "a": "**Wettbewerbsrisiken:** Veränderungen im Wettbewerbsumfeld (Beispiel **Kodak** – Digitalfotografie verschlafen). **Reputationsrisiken:** Ansehen wird beschädigt (Beispiel **VW-Dieselskandal**).", "tags": ["klausur"]},
  {"id": 20, "cat": "B", "label": "Risikoarten", "q": "Technologische Risiken – nenne 2 mit Beispiel.", "a": "**Cyberrisiken:** Cyberangriffe/Datenlecks (Beispiel **WannaCry-Ransomware**). **Innovationsrisiken:** Einführung neuer Technologien/Produkte (Beispiel **Tesla Autopilot**).", "tags": ["klausur"]},
  {"id": 21, "cat": "B", "label": "Risikoarten", "q": "Nenne Beispiele für zeitliche Risiken.", "a": "Verzögerungen im Zeitplan durch unvorhergesehene Ereignisse, Koordinationsprobleme zwischen verschiedenen Gewerken, saisonale Wetterbedingungen, die den Fortschritt beeinträchtigen.", "tags": ["klausur"]},
  {"id": 22, "cat": "B", "label": "Risikoarten", "q": "Nenne Beispiele für Stakeholder-Risiken.", "a": "Widerstand von Anwohnern/Interessensgruppen, Änderungen in den Anforderungen des Auftraggebers, Kommunikationsprobleme zwischen Projektbeteiligten.", "tags": ["klausur"]},
  {"id": 23, "cat": "B", "label": "Risikoarten", "q": "Umwelt- & soziale Risiken – erkläre mit Beispiel.", "a": "**Umweltverschmutzungsrisiken** aus umweltschädlichen Praktiken; **soziale Risiken**, die das Wohlbefinden von Mitarbeitern/Gemeinschaften betreffen (Beispiel **Tschernobyl**); dazu **Naturkatastrophen**.", "tags": ["klausur"]},
  {"id": 24, "cat": "B", "label": "Risikoarten", "q": "Politische & wirtschaftliche Risiken – erkläre mit Beispiel.", "a": "**Politische Instabilität:** Veränderungen in der politischen Landschaft (Beispiel **3. Reich**). **Wirtschaftliche Schwankungen:** Rezession/Abschwung (Beispiel **The Great Depression**).", "tags": ["klausur"]},
  {"id": 25, "cat": "C", "label": "RM-Prozess", "q": "Mit welchen 4 Fragen kommt man im RM zum Ziel?", "a": "1) **Was kann schieflaufen/passieren?** 2) **Was ist die Eintrittswahrscheinlichkeit?** 3) **Was sind mögliche Konsequenzen?** 4) **Ist Vermeidung/Abschwächung möglich?** (z.B. Ampeln an gefährlichen Kreuzungen)", "tags": []},
  {"id": 26, "cat": "C", "label": "RM-Prozess", "q": "Skizziere den Risikomanagementprozess (Regelkreis). (Klausur: Aufbau, welche Phasen & was passiert da)", "a": "Kreislauf um die **Risikostrategie** im Zentrum:", "tags": ["klausur"]},
  {"id": 27, "cat": "C", "label": "RM-Prozess", "q": "Phase 1 – Risikoidentifizierung: Was passiert hier?", "a": "**Erkennen und Dokumentieren** potenzieller Risiken, die das Projekt oder die Organisation betreffen könnten (z.B. strukturierte Risiko-Erfassung). Leitfrage: Was kann schieflaufen?", "tags": []},
  {"id": 28, "cat": "C", "label": "RM-Prozess", "q": "Phase 2 – Risikobewertung: Was passiert hier?", "a": "Analyse der identifizierten Risiken hinsichtlich **Wahrscheinlichkeit und Auswirkung** – mit **qualitativen und quantitativen Methoden** (z.B. Einordnung in eine Matrix Wahrscheinlichkeit × Schadensausmaß).", "tags": []},
  {"id": 29, "cat": "C", "label": "RM-Prozess", "q": "Phase 3 – Risikosteuerung: Was passiert hier?", "a": "**Implementierung der geplanten Maßnahmen** zur Risikominderung, z.B. Schulungen, Anpassung von Prozessen, Aufgabe von Geschäftsbereichen, **Risikotransfer (z.B. Versicherung)**. Merksatz: Ich kann Risiko selber tragen, teilen oder abgeben.", "tags": []},
  {"id": 30, "cat": "C", "label": "RM-Prozess", "q": "Phase 4 – Überwachen & Reporten: Was passiert hier?", "a": "**Kontinuierliche Überwachung** der Risiken und der Wirksamkeit der Maßnahmen (z.B. Risiko-Cockpit) + **Reporting an relevante Stakeholder**, damit alle über den Status informiert sind.", "tags": []},
  {"id": 31, "cat": "C", "label": "RM-Prozess", "q": "Was bedeutet „Review und Verbesserung\" im RM-Prozess?", "a": "**Regelmäßige Überprüfung des gesamten RM-Prozesses** und Anpassung an sich ändernde Rahmenbedingungen (intern und extern).", "tags": []},
  {"id": 32, "cat": "C", "label": "RM-Prozess", "q": "Wie ist eine Risikomatrix aufgebaut und wie erstellt man sie? (evtl. in Klausur selbst erstellen!)", "a": "Achsen: **Eintrittswahrscheinlichkeit** (gering/mittel/hoch, x-Achse) × **Schadenausmaß** (gering/mittel/hoch, y-Achse) → 9 Felder mit Ampelfarben (grün = unkritisch bis rot = kritisch). Jedes identifizierte Risiko wird in das passende Feld eingeordnet; rechts oben = höchste Priorität.", "tags": ["klausur"]},
  {"id": 33, "cat": "C", "label": "RM-Prozess", "q": "Beispiel Bahnreise: Ordne Risiken in die Matrix ein (je 1 Beispiel pro Ecke).", "a": "Gering/gering: Ausfall Bordbistro. Hoch (W'keit)/gering (Schaden): 10–15 Min. Verspätung am Endziel. Hoch/mittel: 15 Min. Verspätung am **Umsteigebahnhof** (Anschluss weg → orange!). Gering/hoch: Komplettausfall des Zuges. Mittel/mittel: Zug hat über 30 Min. Verspätung am Endziel.", "tags": []},
  {"id": 34, "cat": "C", "label": "RM-Prozess", "q": "Risikomatrix – Vorteile (PRO)? (1–2 pro Seite beschreiben können)", "a": "1) **Einfach anwendbar**, intuitiv erfassbar, in der Geschäftswelt vielen vertraut. 2) Deckt **breites Spektrum** des RM ab: für Risikobewertung UND -steuerung einsetzbar. 3) **Zwingt zur Auseinandersetzung** mit Eintrittswahrscheinlichkeiten und Schadenshöhen.", "tags": ["klausur"]},
  {"id": 35, "cat": "C", "label": "RM-Prozess", "q": "Risikomatrix – Nachteile (CONTRA)?", "a": "1) **Reduziert** Risiko auf Häufigkeit & Konsequenz (Ursachen, Linderungsmaßnahmen, Auswirkungen fehlen). 2) Einordnung beruht auf **qualitativer (subjektiver) Einschätzung**. 3) **Statische Sicht** – Risiken ändern sich über die Zeit: entweder aktualisieren oder die Matrix verliert Aussagekraft.", "tags": ["klausur"]},
  {"id": 36, "cat": "C", "label": "RM-Prozess", "q": "Bow-Tie-Diagramm: Nenne die Hauptkomponenten und ihre Position.", "a": "**Gefahr (Hazard):** Mitte – identifiziertes Risiko, Ausgangspunkt der Analyse. **Ursachen (Threats):** links – Faktoren, die das Risiko auslösen/erhöhen. **Folgen (Consequences):** rechts – potenzielle Auswirkungen bei Eintritt (auf Menschen, Umwelt, Wirtschaft). **Kontrollmaßnahmen (Barriers):** zwischen Ursachen↔Risiko und Risiko↔Folgen. **Schwächungsfaktoren:** unten – schwächen die Wirksamkeit der Barrieren.", "tags": []},
  {"id": 37, "cat": "C", "label": "RM-Prozess", "q": "Bow-Tie: Unterschied Präventions- vs. Reaktionsbarriere?", "a": "**Präventionsbarrieren** (links): sollen verhindern, dass eine Ursache zum Risikoeintritt führt. **Reaktionsbarrieren** (rechts): minimieren die Auswirkungen, falls das Risiko eintritt.", "tags": []},
  {"id": 38, "cat": "C", "label": "RM-Prozess", "q": "Bow-Tie – Vorteile (PRO)?", "a": "1) **Visuelle Klarheit:** übersichtliche Darstellung von Risiko, Ursachen, Folgen und Kontrollmaßnahmen – erleichtert das Verständnis für alle Beteiligten. 2) **Strukturierte Analyse:** logische Struktur hilft, Risiken systematisch zu identifizieren und zu analysieren.", "tags": []},
  {"id": 39, "cat": "C", "label": "RM-Prozess", "q": "Bow-Tie – Nachteile (CONTRA)?", "a": "1) **Komplexität bei großen Systemen:** bei vielen Wechselwirkungen wird es unübersichtlich, wichtige Details gehen verloren. 2) **Subjektivität:** Identifikation von Ursachen, Folgen und Barrieren hängt von Erfahrung/Wissen der Beteiligten ab.", "tags": []},
  {"id": 40, "cat": "C", "label": "RM-Prozess", "q": "Welche 4 Handlungsoptionen gibt es im Umgang mit Risiken?", "a": "1) **Vermeiden** (Aufgabe/Abstoßen – meist schwierig), 2) **Verringern/Reduzieren** (Schulungen, Limitierungen, zusätzliche Ressourcen), 3) **(!) Überwälzung/Transfer** (streuen, verteilen, Teilübertrag → Versicherung!), 4) **(!) Selbsttragung/Akzeptieren.**", "tags": []},
  {"id": 41, "cat": "C", "label": "RM-Prozess", "q": "Handlungsbaum: Ich behalte ein Risiko bewusst bei mir – was kann ich tun?", "a": "**1) Risiko kontrollieren:** vor Eintritt **verhindern** (Sicherheitsvorschriften, Wartungen, Schulungen), nach Eintritt **reduzieren** (Krisenorganisation, Notfallpläne, schnelle Reparaturprozesse). **2) Risiko finanzieren** (intern organisieren): sparen, oder warten bis es passiert und dann zahlen (ggf. Bankkredit) → so lassen sich Risiken auch im größeren Stil finanzieren.", "tags": []},
  {"id": 42, "cat": "D", "label": "Risikomaße", "q": "Was misst die Volatilität?", "a": "Die **Schwankungen** einer Größe. Je höher die Volatilität, desto höher die Abweichung vom Mittelwert.", "tags": []},
  {"id": 43, "cat": "D", "label": "Risikomaße", "q": "Was ist die Standardabweichung (Definition + Interpretation)?", "a": "Die **Streubreite einer Variablen um den Mittelwert** – wie stark streuen einzelne Werte um den Mittelwert? Gleiche Einheit wie die Daten selbst (z.B. Jahre). 🎯 Rechnen können!", "tags": []},
  {"id": 44, "cat": "D", "label": "Risikomaße", "q": "Was ist die Varianz?", "a": "Die **quadrierte durchschnittliche Entfernung vom Mittelwert** (Einheit: quadriert, z.B. Jahre²). Die Standardabweichung ist die Wurzel daraus.", "tags": []},
  {"id": 45, "cat": "D", "label": "Risikomaße", "q": "Formel und Rechenschritte für die Standardabweichung σ? (Formel VOR der Rechnung lernen!)", "a": "σ = √( (1/n) · Σ(xᵢ − x̄)² ), mit n = Anzahl, xᵢ = Einzelwert, x̄ = Mittelwert.", "tags": ["rechnen"]},
  {"id": 46, "cat": "D", "label": "Risikomaße", "q": "Berechne σ für die Alter: 18, 24, 22, 18, 22, 25, 19, 20. („sowas müssen wir rechnen können\")", "a": "1) x̄ = 168/8 = **21**. 2) Abweichungen: −3, 3, 1, −3, 1, 4, −2, −1. 3) Quadrate: 9, 9, 1, 9, 1, 16, 4, 1. 4) Summe = **50**. 5) Varianz = 50/8 = **6,25 Jahre²**. 6) σ = √6,25 = **2,5 Jahre**.", "tags": ["rechnen"]},
  {"id": 47, "cat": "D", "label": "Risikomaße", "q": "Wie interpretierst du σ = 2,5 Jahre bei Mittelwert 21?", "a": "Die Werte streuen im Schnitt um **±2,5 Jahre** um den Mittelwert 21 – bei Normalverteilung liegen ca. **68 %** der Werte im Bereich 18,5–23,5 Jahre. 🎯 Interpretation ist wichtig!", "tags": []},
  {"id": 48, "cat": "D", "label": "Risikomaße", "q": "Was ändert sich bei einer Stichprobe (statt Grundgesamtheit)?", "a": "Man teilt durch **n−1** statt n: Varianz = 50/7 ≈ **7,14 Jahre²**, σ ≈ **2,67 Jahre**.", "tags": []},
  {"id": 49, "cat": "D", "label": "Risikomaße", "q": "Normalverteilung: Wie viele Daten liegen innerhalb von 1, 2 und 3 Standardabweichungen?", "a": "~**68 %** innerhalb ±1σ, ~**95 %** innerhalb ±2σ, ~**99,7 %** innerhalb ±3σ. (Standardnormalverteilung: μ = 0, σ = 1; Wendestellen der Glockenkurve bei μ±σ.) Merkbild: Die meisten Menschen sind ungefähr gleich groß (68 %), manche etwas größer/kleiner (95 % bei 2σ).", "tags": []},
  {"id": 50, "cat": "D", "label": "Risikomaße", "q": "Definiere den Value-at-Risk (VaR).", "a": "Der **absolute Wertverlust** einer im Unternehmen definierten Risikoposition, der mit einer zuvor bestimmten **Wahrscheinlichkeit (Konfidenzniveau)** innerhalb eines fest bestimmten **Zeitraums (Halteperiode)** **nicht überschritten** wird.", "tags": []},
  {"id": 51, "cat": "D", "label": "Risikomaße", "q": "Wie wird der VaR im Versicherungskontext (Solvency II) konkret genutzt?", "a": "Frage: **Wie viel Kapital muss das VU halten, um das nächste Jahr mit 99,5 % Wahrscheinlichkeit zu überleben?** → VaR mit Konfidenzniveau **99,5 %** und Halteperiode **1 Jahr** (Basis des SCR).", "tags": []},
  {"id": 52, "cat": "D", "label": "Risikomaße", "q": "Nenne die 4 Nachteile des VaR.", "a": "1) **Annahme der Normalverteilung** der Risiken, 2) beschreibt nur den Wert **bei** Überschreiten des Konfidenzniveaus, nicht den tatsächlichen/erwarteten Verlust dahinter, 3) Fokus auf Verlust**wahrscheinlichkeit**, 4) Berechnung meist auf Basis **historischer Daten**.", "tags": []},
  {"id": 53, "cat": "D", "label": "Risikomaße", "q": "Was ist der Tail Value-at-Risk (TVaR)?", "a": "Er geht einen Schritt weiter als der VaR: der **durchschnittliche Verlust, falls der VaR bereits überschritten wurde** – also der Durchschnitt im Extrembereich („Wenn es schlechter läuft als die Schwelle, wie groß sind dann im Schnitt die Verluste?\").", "tags": []},
  {"id": 54, "cat": "D", "label": "Risikomaße", "q": "VaR vs. TVaR – Merksatz + warum ist TVaR oft „besser\"?", "a": "**VaR = Grenzwert** („Mit 95 % verliere ich nicht mehr als X\"). **TVaR = Durchschnitt der Verluste jenseits des Grenzwerts.** TVaR ist oft aussagekräftiger, weil der VaR nichts darüber sagt, **wie schlimm** es hinter der Schwelle wird – der TVaR berücksichtigt genau diesen „schlimmen Rest\" (Extremrisiken).", "tags": []},
  {"id": 55, "cat": "E", "label": "Rahmen & Stakeholder", "q": "Welche Rahmenbedingungen wirken auf das Risikomanagement? (🎯 nicht alle auswendig lernen – Kategorien + je 2 Beispiele reichen)", "a": "**Rechtlich/Gesetzgebung:** Solvency II, VAG, VAIT/DORA, Corporate Governance, EU-Taxonomie (ESG). **(Volks-)wirtschaftlich:** Rezession, Zinsniveau, Arbeitsmarkt, Handelsbarrieren/Zölle, politische Stabilität, sozioökonomische Trends (Demographie, Einkommensverteilung, Konsumverhalten). **Technologischer Fortschritt:** kürzere Produktzyklen, IT, Cybergefahren, KI. **Ressourcen:** Mitarbeiter, Budget.", "tags": ["klausur"]},
  {"id": 56, "cat": "E", "label": "Rahmen & Stakeholder", "q": "Wer sind die Interessensgruppen des Risikomanagements eines VU?", "a": "**Zedenten, Kunden, Mitarbeiter, Aufsicht (BaFin; EU-Ebene: EIOPA), Investoren/Aktionäre, Peers** (Wettbewerber).", "tags": []},
  {"id": 57, "cat": "E", "label": "Rahmen & Stakeholder", "q": "Risk Reports sollen interpretiert/diskutiert werden 🎯 – worauf achtest du?", "a": "Was sind die **Top-Risiken** (Wahrscheinlichkeit × Auswirkung)? Wie ist der **Trend** (neu/verschärft/entschärft)? Welche **Maßnahmen** laufen, und passt die Risikolage zur **Risikostrategie**? Immer einordnen: Was bedeutet das fürs Unternehmen, was würde ich dem Management empfehlen?", "tags": []},
  {"id": 58, "cat": "F", "label": "Solvency II", "q": "Was bedeutet Aktiv-Passiv-Management (ALM) im VU? Beispiel!", "a": "Die Kapitalanlagen (Aktivseite) werden so gesteuert, dass das Geld **zeitlich genau dann verfügbar ist, wenn die Verpflichtungen (Passivseite) es brauchen**. Beispiel: Prämie einer 5-monatigen Feuerrohbauversicherung lege ich nicht langfristig an (Geld kann jederzeit gebraucht werden); Beiträge einer Versicherung mit 20 Jahren Laufzeit kann ich dagegen bis zu 20 Jahre anlegen.", "tags": []},
  {"id": 59, "cat": "F", "label": "Solvency II", "q": "Was ist der Kern von Solvency II? Was heißt „risikobasiert\"?", "a": "Kern: **risikobasierte Eigenmittelausstattung mit 3-Säulen-Ansatz.** Risikobasiert = das VU muss sich im Klaren sein, **welche Risiken es hat, und muss diese selbst managen** (z.B. durch Rückversicherung).", "tags": []},
  {"id": 60, "cat": "F", "label": "Solvency II", "q": "Nenne die 3 Säulen von Solvency II.", "a": "**Säule 1: Quantitative Anforderungen** (Solvabilitätsübersicht, Eigenmittelausstattung, Solvenzkapitalanforderungen – „rechnen\"). **Säule 2: Qualitative Anforderungen** (Governance-System, Risikomanagement inkl. ORSA). **Säule 3: Markttransparenz** (quantitative und narrative Berichte an Aufsicht und Öffentlichkeit).", "tags": ["klausur"]},
  {"id": 61, "cat": "F", "label": "Solvency II", "q": "SCR vs. MCR – was ist der Unterschied?", "a": "**SCR (Solvency Capital Requirement):** regulatorische Solvabilitätsanforderung, Berechnung per **Standardformel oder (partiellem) internem Modell**, basiert auf **VaR mit Konfidenzniveau 99,5 %**. **MCR (Minimum Capital Requirement):** regulatorische **Untergrenze**, nur Basiseigenmittel anrechenbar – Unterschreiten führt zu **aufsichtsrechtlichen Maßnahmen**.", "tags": []},
  {"id": 62, "cat": "F", "label": "Solvency II", "q": "Was ist der ORSA-Bericht (Säule 2)?", "a": "**Own Risk and Solvency Assessment:** Das VU muss sich selbst **Szenarien ausdenken und durchrechnen** – was würden diese auslösen? Beispiele: Cyberangriff, Pandemie, Finanzmarktkrise, Krieg. Worst-Case-Szenarien definieren, Auswirkungen berechnen und risikomindernde Faktoren (davor & danach) benennen.", "tags": []},
  {"id": 63, "cat": "F", "label": "Solvency II", "q": "Welche Berichte gehören zu Säule 3 (Transparenz)?", "a": "**SFCR** (Solvency and Financial Condition Report): an die **Öffentlichkeit**, jährlich. **RSR** (Regular Supervisory Reporting): an die **Aufsicht**, nicht öffentlich, mindestens alle 3 Jahre. **QRT** (Quantitative Reporting Templates): an die Aufsicht (Auszüge auch im SFCR), jährlich, einige vierteljährlich.", "tags": []},
  {"id": 64, "cat": "F", "label": "Solvency II", "q": "In welche 4 Risikokategorien teilt Solvency II die Risiken eines VU ein?", "a": "1) **Versicherungstechnische Risiken** (Leben / Kranken / Nicht-Leben), 2) **Operationelle Risiken**, 3) **Markt-/Finanzrisiken**, 4) **Ausfallrisiken.** (Die Solvenzkapitalanforderung wird nach festem Muster berechnet – Struktur ist vorgegeben.)", "tags": []},
  {"id": 65, "cat": "F", "label": "Solvency II", "q": "Was sind operationelle Risiken? Beispiele!", "a": "Risiken **im eigenen Betrieb**: fehlerhafte Prozesse, Menschen, Systeme, Rechtsrisiken. Beispiele: **Betrug** (Mitarbeiter zahlen sich selbst Geld aufs Konto), **menschliche Fehler** z.B. in der IT.", "tags": []},
  {"id": 66, "cat": "G", "label": "Vt. Risiken", "q": "Zähle die versicherungstechnischen Risiken auf.", "a": "1) **Zufallsrisiko**, 2) **Kumulrisiko**, 3) **Ansteckungsrisiko**, 4) **Großschaden-/Katastrophenrisiko**, 5) **Änderungsrisiko**, 6) **Irrtumsrisiko** (Diagnose-/Prognoserisiko), 7) **Asymmetrische Informationsverteilung** (Adverse Selection, Moral Hazard).", "tags": []},
  {"id": 67, "cat": "G", "label": "Vt. Risiken", "q": "Erkläre kurz: Zufalls-, Kumul-, Ansteckungs- und Großschadenrisiko.", "a": "**Zufallsrisiko:** der tatsächliche Schadenverlauf weicht rein zufällig vom erwarteten ab. **Kumulrisiko:** viele versicherte Risiken werden von **einem Ereignis** gleichzeitig getroffen (z.B. Sturm). **Ansteckungsrisiko:** ein Schaden greift auf weitere Risiken über. **Großschaden-/Katastrophenrisiko:** einzelne extrem hohe Schäden.", "tags": []},
  {"id": 68, "cat": "G", "label": "Vt. Risiken", "q": "Änderungsrisiko: In welchen 4 Dimensionen können sich Risikogrundlagen ändern?", "a": "**Wirtschaftlich** (Inflation, Wertekonzentration), **gesellschaftlich** (Anstieg Kriminalität, Terrorgefahr), **technologisch** (Nuklearenergie, Medikamente), **rechtlich/staatlich** (Änderung Haftungsrecht, Umkehr der Beweislast).", "tags": []},
  {"id": 69, "cat": "G", "label": "Vt. Risiken", "q": "Was ist das Irrtumsrisiko?", "a": "Auch **Diagnose-/Prognoserisiko**: Die Kalkulation beruht auf einer **falschen Datengrundlage bzw. falsch eingeschätzten Schadenverteilung** – das Risiko wurde von Anfang an falsch eingeschätzt (≠ Änderungsrisiko, wo sich die Welt nachträglich ändert).", "tags": []},
  {"id": 70, "cat": "G", "label": "Vt. Risiken", "q": "Asymmetrische Informationsverteilung: Adverse Selection vs. Moral Hazard?", "a": "**Adverse Selection** (vor Vertragsschluss): vor allem schlechte Risiken fragen Versicherung nach, weil sie ihr Risiko besser kennen als das VU. **Moral Hazard** (nach Vertragsschluss): Versicherte verhalten sich riskanter/unvorsichtiger, weil sie versichert sind.", "tags": []},
  {"id": 71, "cat": "G", "label": "Vt. Risiken", "q": "Welche 4 Ausgleichs-/Diversifikationsmöglichkeiten hat ein VU?", "a": "1) Diversifikation **über Regionen** (z.B. Kumulrisiko abschwächen), 2) **über Zeit**, 3) **über Sparten**, 4) **Gesetz der großen Zahlen** (großes Portfolio → Schwankungen gleichen sich aus).", "tags": []},
  {"id": 72, "cat": "G", "label": "Vt. Risiken", "q": "Welches versicherungstechnische Risiko lässt sich kaum abschwächen?", "a": "Das **rechtliche/staatliche Änderungsrisiko**. Alle anderen lassen sich grundsätzlich abschwächen – z.B. durch Ausgleich über Regionen, Auslagerung oder Regulierung der Annahme (z.B. Gesundheitsfragen).", "tags": []},
  {"id": 73, "cat": "G", "label": "Vt. Risiken", "q": "In welchen Sparten ist das Kumulrisiko praktisch „egal\"?", "a": "**Leben, Kfz, Haftpflicht (HP), Unfall** – dort treten kaum Kumulrisiken auf.", "tags": []},
  {"id": 74, "cat": "H", "label": "Liquidität & SchwaRü", "q": "Welche Chancen bietet eine gute Liquiditätssteuerung im VU? (5)", "a": "1) **Zahlungsfähigkeit sichern** (keine Engpässe bei Schadenzahlungen, RV-Abrechnungen, Betriebskosten), 2) **bessere Krisenfestigkeit** (Puffer → keine Notverkäufe mit Verlust), 3) **mehr strategischer Spielraum** (Investitionen, Underwriting, Kapitalallokation planbar), 4) **höheres Vertrauen** bei Aufsicht, Rückversicherern, Partnern, 5) **bessere Rentabilität** (überschüssige Liquidität effizient einsetzen statt unproduktiv liegen lassen).", "tags": []},
  {"id": 75, "cat": "H", "label": "Liquidität & SchwaRü", "q": "Welche Liquiditätsrisiken hat ein VU? (4)", "a": "1) **Liquiditätsengpass/Zahlungsunfähigkeit** (fällige Schäden, Rückkäufe, RV-Verpflichtungen nicht rechtzeitig zahlbar), 2) **Realisierungsverluste** (Notverkäufe in Stressphasen mit Abschlägen), 3) **Asset-Liability-Mismatch** (Fristigkeit/Charakter der Anlagen passt nicht zu den Verpflichtungen), 4) **regulatorische und Reputationsrisiken** (verunsicherte Aufsicht, Ratingagenturen, Investoren → Rating-Herabstufung, Eingriffe, Kundenverlust).", "tags": []},
  {"id": 76, "cat": "H", "label": "Liquidität & SchwaRü", "q": "Risikoausgleichsmodelle: Welche Möglichkeiten hat ein VU, Risiken zu begrenzen/abzufedern?", "a": "**Risikoreserven:** bilanzielles Eigenkapital, **Schwankungsrückstellungen** (Glättung der Ergebnisse), weitere diverse Rückstellungen, freie RfB, stille Reserven (HGB), Mobilisierungsreserven. Außerdem: **Kapitalerhöhungen/Nachschusspflichten** sowie **Rückversicherung und ART.**", "tags": []},
  {"id": 77, "cat": "H", "label": "Liquidität & SchwaRü", "q": "Bei welcher Rechtsform gibt es Nachschusspflichten?", "a": "In deiner Zusammenfassung steht „bei AGs\" – **klassisch ist die Nachschusspflicht aber ein Merkmal des VVaG** (Versicherungsverein auf Gegenseitigkeit; Satzung kann Nachschüsse der Mitglieder vorsehen). Bei der AG sind Aktionäre nur zur Einlage verpflichtet. → Im Zweifel mit den Folien/OneNote abgleichen, vermutlich Tippfehler.", "tags": ["achtung"]},
  {"id": 78, "cat": "H", "label": "Liquidität & SchwaRü", "q": "Wozu dienen Schwankungsrückstellungen (SchwaRü) und wie funktionieren sie?", "a": "Sie **glätten die Ergebnisse über die Jahre**: In guten Jahren wird zugeführt, in schlechten entnommen. Wichtig: Befüllung/Entnahme ist **nicht freiwillig**, sondern erfolgt, **wenn die (gesetzlichen) Kriterien erfüllt sind.**", "tags": []},
  {"id": 79, "cat": "I", "label": "RV-Fachbegriffe", "q": "Was ist ein Pool? Beispiel!", "a": "Zusammenschluss mehrerer Versicherer, um eigentlich **nicht versicherbare Risiken** gemeinsam zu versichern – z.B. der **Atompool**.", "tags": []},
  {"id": 80, "cat": "I", "label": "RV-Fachbegriffe", "q": "Warum gibt man manche Risiken an den Kapitalmarkt?", "a": "Weil dort zusätzliche Träger wie **Hedgefonds** etc. sitzen, die z.B. **Naturgefahren**-Risiken übernehmen können (zusätzliche Kapazität neben der RV).", "tags": []},
  {"id": 81, "cat": "I", "label": "RV-Fachbegriffe", "q": "Welche Vertragsbeziehung hat der Versicherungsnehmer zum Rückversicherer?", "a": "**Keine!** Der VN hat nur Kontakt zum Erst-VU. Bei der RV hat der Kunde nie Kontakt zum Rückversicherer – es besteht keine Vertragsbeziehung (RV = „Versicherung der Versicherung\").", "tags": []},
  {"id": 82, "cat": "I", "label": "RV-Fachbegriffe", "q": "Mitversicherung vs. Rückversicherung?", "a": "**Mitversicherung:** z.B. ein Großunternehmen gibt 1 Risiko an **mehrere Erst-VU gleichzeitig** (z.B. jedes trägt 10 %) – alle haben Vertrag mit dem VN. **Rückversicherung:** Vertrag zwischen **Erst-VU und RV, unabhängig vom VN.**", "tags": []},
  {"id": 83, "cat": "I", "label": "RV-Fachbegriffe", "q": "Vertrags-(obligatorische) vs. fakultative Rückversicherung?", "a": "**Obligatorisch:** meist **ganze Bestände** werden abgegeben – niemand kann sich „Kirschen rauspicken\", es **müssen** alle Risiken gegeben/genommen werden. **Fakultativ:** **Einzelrisikoprüfung** – Zedent entscheidet frei über Abgabe, RV frei über Annahme.", "tags": []},
  {"id": 84, "cat": "I", "label": "RV-Fachbegriffe", "q": "Was ist ein „professioneller\" Rückversicherer?", "a": "Ein Unternehmen, das **(fast) ausschließlich Rückversicherung** betreibt.", "tags": []},
  {"id": 85, "cat": "I", "label": "RV-Fachbegriffe", "q": "Passive vs. aktive Rückversicherung?", "a": "**Passiv:** Erst-VU **gibt Risiko ab** (VU als Nachfrager von RV-Schutz). **Aktiv:** RV **betreibt** Rückversicherung als Anbieter/Annehmer.", "tags": []},
  {"id": 86, "cat": "I", "label": "RV-Fachbegriffe", "q": "Zedent vs. Zessionär?", "a": "**Zedent** = Erst-VU, gibt ab (betreibt passive RV). **Zessionär** = Rückversicherer, nimmt an (aktive RV).", "tags": []},
  {"id": 87, "cat": "I", "label": "RV-Fachbegriffe", "q": "Was bedeutet Erneuerung/Renewal?", "a": "RV-Verträge laufen meist **1 Jahr** und werden zu einem bestimmten (länderabhängigen) Datum **erneuert**.", "tags": []},
  {"id": 88, "cat": "I", "label": "RV-Fachbegriffe", "q": "Was ist Retrozession?", "a": "Die **Rückversicherung des Rückversicherers** – der RV gibt selbst Risiken weiter.", "tags": []},
  {"id": 89, "cat": "I", "label": "RV-Fachbegriffe", "q": "Brutto vs. Netto?", "a": "**Brutto = alles VOR Rückversicherung, Netto = alles NACH Rückversicherung** (gilt für Beiträge, Schäden, Quoten ...).", "tags": []},
  {"id": 90, "cat": "I", "label": "RV-Fachbegriffe", "q": "Proportional vs. nicht-proportional – Grundidee?", "a": "**Proportional:** Risiko wird zu einem festen Anteil abgegeben (z.B. 20 %) – Prämie und Schaden werden im selben Verhältnis geteilt. **Nicht-proportional:** RV zahlt erst, wenn der **Schaden** eine Schwelle überschreitet.", "tags": []},
  {"id": 91, "cat": "I", "label": "RV-Fachbegriffe", "q": "Severity vs. Frequency?", "a": "**Severity:** einzelne **Großschäden**, die Sorgen machen. **Frequency:** **viele kleine Schäden**, die in Summe auch zum Problem werden.", "tags": []},
  {"id": 92, "cat": "I", "label": "RV-Fachbegriffe", "q": "Was ist ein Layer (Layering)?", "a": "**Abschnitte der Gesamthaftung** – die „Schichtung\" der Rückversicherung, wenn man mehrere Deckungen übereinanderlegt (Säulen-Darstellung in der Übungsaufgabe).", "tags": []},
  {"id": 93, "cat": "J", "label": "Magischer Würfel", "q": "Welche 3 Achsen hat der magische Würfel der RV – und was ist die 4. Dimension?", "a": "Achsen: **1) LoB (Lines of Business / Sparten:** eine/wenige ↔ viele), **2) Portefeuillegröße** (klein ↔ groß), **3) Geographie** (lokal/national ↔ international/weltweit). **4. Dimension = Zeit** (zeitlicher Aspekt). Wer auf den Achsen schwach aufgestellt ist, „outsourct\" die fehlende Diversifikation an den Rückversicherer.", "tags": ["klausur"]},
  {"id": 94, "cat": "J", "label": "Magischer Würfel", "q": "Diversifikation über LoB (Sparten) – warum funktioniert sie und wo ist die Grenze?", "a": "Sparten sind i.d.R. **recht unabhängig** voneinander → sie gleichen sich aus. ABER: Manchmal sind Sparten korreliert, z.B. **Hausrat & Wohngebäude bei Sturm.**", "tags": ["klausur"]},
  {"id": 95, "cat": "J", "label": "Magischer Würfel", "q": "Diversifikation über Portefeuillegröße – Situation in Deutschland?", "a": "In D hat man i.d.R. **genug Verträge im Bestand**, um durch Größe zu diversifizieren – der Bestand ist groß genug, um gewisse Schwankungen abzufedern (Gesetz der großen Zahlen).", "tags": ["klausur"]},
  {"id": 96, "cat": "J", "label": "Magischer Würfel", "q": "Diversifikation über Geographie – Problem lokal begrenzter VU?", "a": "Lokal begrenzte VU können geographisch **nicht** diversifizieren: Tritt ein Schaden(ereignis) ein, ist evtl. der **ganze Bestand betroffen.** Weltweit: Wenn es in D einen Schaden gibt, ist Japan wahrscheinlich nicht betroffen.", "tags": ["klausur"]},
  {"id": 97, "cat": "J", "label": "Magischer Würfel", "q": "4. Dimension Zeit: Warum ist der Ausgleich über die Zeit für ein VU problematisch? (4 Punkte)", "a": "1) **Bilanz zwingt zur 1-Jahres-Sicht** – entgegen dem Versicherungsprinzip ist der Zeitraum zu kurz für den Ausgleich über die Zeit (z.B. Jahr mit Überschäden). 2) **Stakeholder erwarten Stabilität** (Ergebnisse, Dividenden) – Investoren verstehen Versicherungsvolatilität nicht → Glättung nötig (z.B. SchwaRü), sonst unzufriedene Investoren. 3) **Solvenzquoten** müssen jederzeit erfüllt sein. 4) **Aufbauphasen:** Ein Startup ist in allen 4 Dimensionen schwach – in einem Jahr laufen selten alle Dimensionen gut.", "tags": ["klausur"]},
  {"id": 98, "cat": "J", "label": "Magischer Würfel", "q": "Fazit aus dem magischen Würfel: Warum kauft man Rückversicherung?", "a": "Wer in einer oder mehreren Dimensionen (Sparten, Größe, Geographie, Zeit) **nicht ausreichend selbst diversifizieren** kann, **lagert diesen Ausgleich an den Rückversicherer aus** („Outsourcing\" der Diversifikation) – der RV hat die Diversifikationseffekte, die dem Zedenten fehlen.", "tags": ["klausur"]},
  {"id": 99, "cat": "K", "label": "Funktionen der RV", "q": "Nenne die Funktionsblöcke der Rückversicherung (Überblick).", "a": "1) **Risikotragung**, 2) **Finanzierung von Risiken**, 3) **Glättung der versicherungstechnischen Ergebnisse** / Stabilisierung der GuV / EK-Schutz, 4) **strategische Nutzung**, 5) **Beratung/Unterstützung des Zedenten** – plus **volkswirtschaftliche Bedeutung.**", "tags": []},
  {"id": 100, "cat": "K", "label": "Funktionen der RV", "q": "Was ist die wichtigste Funktion der RV?", "a": "Die **Risikotragung**: der **Transfer versicherungstechnischer Risiken auf die Bilanz des RV** – plus Streuung/Atomisierung und damit Heben von Diversifikationseffekten (Effekte, die der Zedent nicht hat, hat vielleicht der RV).", "tags": []},
  {"id": 101, "cat": "K", "label": "Funktionen der RV", "q": "Finanzierungsfunktion – erkläre „Eigenkapitalsubstitut/Erhöhung der Zeichnungskapazität\" am Beispiel.", "a": "Ich darf laut Zeichnungsrichtlinien nur bis **1 Mio.** zeichnen, der Kunde will **2 Mio.** Optionen: 1) ablehnen, 2) entgegen den Zeichnungsrichtlinien zeichnen (schlecht), 3) **1 Mio. an den RV abgeben** → RV wirkt als EK-Ersatz (ökonomisch – HGB; SII) und erhöht die Zeichnungskapazität.", "tags": []},
  {"id": 102, "cat": "K", "label": "Funktionen der RV", "q": "Was bedeutet „Vorfinanzierung von Abschlusskosten\"?", "a": "Ich bekomme die Prämie laufend (z.B. **100 €/Monat**), muss aber **sofort z.B. 4.000 € Provision** an den Vermittler zahlen → Liquiditätsrisiko. Die RV (insb. mit RV-Provision) hilft, diese Anlaufkosten vorzufinanzieren.", "tags": []},
  {"id": 103, "cat": "K", "label": "Funktionen der RV", "q": "Formel: Versicherungstechnisches Ergebnis?", "a": "**Vt. Ergebnis = Prämie − Schäden − Kosten.** (Brutto: ohne RV; Netto: nach RV-Anteilen.)", "tags": ["rechnen"]},
  {"id": 104, "cat": "K", "label": "Funktionen der RV", "q": "Glättungsfunktion: Was ist der Trade-off?", "a": "Die RV **nimmt Volatilität raus – aber zu einem Preis**: Sie kostet Geld, langfristig zahle ich mehr Prämie an den RV als ich Leistung zurückbekomme. Dafür bekomme ich eine **stabile Netto-Ergebnislinie** (wichtig für Stakeholder).", "tags": []},
  {"id": 105, "cat": "K", "label": "Funktionen der RV", "q": "Welche strategischen Nutzungen der RV gibt es?", "a": "Steuerung von **Bilanz und/oder GuV** (z.B. SchwaRü), **Finanzrückversicherung**, **Ergebnisstützung/Platzierungshilfe**, **konzerninterne Steuerung und Kapitalallokation.**", "tags": []},
  {"id": 106, "cat": "K", "label": "Funktionen der RV", "q": "Wie unterstützt der RV den Zedenten über die Risikotragung hinaus?", "a": "**Beratung/Unterstützung:** Erschließung neuer Geschäftsfelder, Unterstützung in der **Produktentwicklung**, Bereitstellung von **Tools** (z.B. zur Risikoprüfung), **Begleitung von Sanierungsmaßnahmen.**", "tags": []},
  {"id": 107, "cat": "K", "label": "Funktionen der RV", "q": "Welche volkswirtschaftliche Bedeutung hat die RV?", "a": "1) Bereitstellung von **weltweitem Risikokapital**, 2) **Versicherbarkeit** vieler Risiken wird oft erst durch RV möglich, 3) RV sind **bedeutende Investoren** (z.B. Infrastrukturmaßnahmen, Staatsanleihen).", "tags": []},
  {"id": 108, "cat": "K", "label": "Funktionen der RV", "q": "Grafik „Verlauf Brutto-RV-Netto\": Wie hängen die drei Linien zusammen und was ist die Hauptmotivation?", "a": "**Netto = Brutto − RV(-Ergebnis).** Hauptmotivation: **Glättung der versicherungstechnischen Ergebnisse.** Im sehr guten Jahr gebe ich mehr an den RV ab, als ich von ihm bekomme; im Schadenjahr erstattet der RV viel. Achtung: RV ist **kein Allheilmittel** – kleine vt. Verluste netto sind ok; ein Dip nur in einer Sparte ist kein Problem, ein konzernweiter schon (Investoren!). Negativseite der Glättung: Nach einem Top-Jahr sieht netto „weniger toll\" aus, und über lange Sicht kostet die Abgabe an den RV Geld.", "tags": []},
  {"id": 109, "cat": "L", "label": "Proportionale RV", "q": "Zeichne den Überblicksbaum der RV-Formen aus dem Kopf. (einordnen können + wissen was was ist)", "a": "**Rückversicherung** → **Vertrags-RV** (alle Risiken müssen gegeben/genommen werden) und **fakultative RV** (nur einzelne Risiken). Beide jeweils **proportional** und **nicht-proportional.** Vertragstypen: proportional → **Quote** und **Summenexzedent**; nicht-proportional → **Schadenexzedent pro Risiko (XL/R)**, **Schadenexzedent pro Ereignis (XL/E)**, **Stop Loss (SL)**.", "tags": ["klausur"]},
  {"id": 110, "cat": "L", "label": "Proportionale RV", "q": "Proportional vs. nicht-proportional: Bezugsgröße und Prämie?", "a": "**Proportional:** Bezugsgröße = **Risiko** (VSU/PML), Prämie = **anteilig original.** **Nicht-proportional:** Bezugsgröße = **Schaden**, Prämie = **unabhängig vom Original.**", "tags": []},
  {"id": 111, "cat": "L", "label": "Proportionale RV", "q": "Wie funktioniert die Quotenrückversicherung?", "a": "Einfachste Form der RV: Ein **fester Prozentsatz jedes Risikos** wird abgegeben. Bei z.B. 30 % Quote werden **Prämie UND Schaden 70/30** aufgeteilt (30 % beim RV, 70 % beim VU) – unabhängig von der Größe des Einzelrisikos.", "tags": []},
  {"id": 112, "cat": "L", "label": "Proportionale RV", "q": "Was ist die RV-Provision und welche Formen gibt es?", "a": "Der RV **erstattet dem Zedenten** eine Provision, um dessen **Abschluss- und Betriebskosten** zu decken (die der Zedent ja allein trägt). Sie ist quasi der **„Preis\" der proportionalen Deckung.** Formen: 1) **fixer Prozentsatz** der Prämie, 2) **variabler Satz = Staffelprovision** (abhängig vom Schadenverlauf), 3) **Originalkostenerstattung.**", "tags": []},
  {"id": 113, "cat": "L", "label": "Proportionale RV", "q": "Formeln bei der Quote (Abgabequote q)? (Formel vor der Rechnung!)", "a": "RV-Beitrag = **q × Bruttobeitrag** · RV-Schadenanteil = **q × Bruttoschaden** · Nettobeitrag = **(1−q) × Bruttobeitrag** · Nettoschaden = **(1−q) × Bruttoschaden.**", "tags": ["rechnen"]},
  {"id": 114, "cat": "L", "label": "Proportionale RV", "q": "Rechne: Bruttoprämie 1.000 €, Quote 20 %, Schäden 700 €, Kosten 100 €. Brutto- und Netto-vt.-Ergebnis?", "a": "**Brutto:** 1.000 − 700 − 100 = **200 €.** **RV-Ströme:** −200 € Prämienabgabe (20 % von 1.000), +140 € Schadenerstattung (20 % von 700). **Netto:** 1.000 − 200 − 700 + 140 − 100 = **140 €.** ⚠️ In der Zusammenfassung steht „= 200 € vt. Ergebnis\" – das ist das **Brutto**ergebnis; netto sind es 140 € (eine evtl. RV-Provision käme netto noch dazu).", "tags": ["rechnen", "achtung"]},
  {"id": 115, "cat": "L", "label": "Proportionale RV", "q": "Quote: Vorteile?", "a": "1) **Effizienter, leicht steuerbarer EK-Ersatz.** 2) **Transferiert auch die Auswirkungen von Änderungs- und Irrtumsrisiken** (weil der RV an JEDEM Schaden anteilig beteiligt ist – auch wenn der ganze Bestand schlechter läuft als kalkuliert).", "tags": []},
  {"id": 116, "cat": "L", "label": "Proportionale RV", "q": "Quote: Nachteile?", "a": "1) **Hoher absoluter Gewinnabfluss auch in positiven Jahren** möglich. 2) **Entlastung auch in Jahren geringen Schadenaufwands** – ich gebe Prämie ab, obwohl ich die Entlastung gar nicht gebraucht hätte.", "tags": []},
  {"id": 117, "cat": "L", "label": "Proportionale RV", "q": "Wie funktioniert der Summenexzedent (SuEx)?", "a": "Aufteilung **nach Größe des Einzelrisikos**: Bis zum **Selbstbehalt/Maximum** (z.B. 150.000 €) behält das VU alles selbst; was darüber liegt, übernimmt der RV – begrenzt auf eine Anzahl **Maxima** (z.B. 10 Maxima → RV-Kapazität = 10 × Maximum). Für jedes Risiko ergibt sich so eine **individuelle Quote**, mit der dann Prämie und Schaden geteilt werden. Kleine Risiken (≤ Maximum) bleiben zu 100 % beim VU.", "tags": []},
  {"id": 118, "cat": "L", "label": "Proportionale RV", "q": "SuEx-Formeln: Abgabequote und behaltener Anteil je Risiko? (Formel vor der Rechnung!)", "a": "**Abgabequote qᵢ = (VSUᵢ − Maximum) / VSUᵢ** (mind. 0; RV-Anteil zusätzlich durch Anzahl Maxima begrenzt). **Behaltener Anteil = Maximum / VSUᵢ.** Mit qᵢ werden dann **Beitrag und Schaden dieses Risikos** geteilt: RV-Beitragᵢ = qᵢ × Beitragᵢ, Nettoschadenᵢ = (1−qᵢ) × Schadenᵢ.", "tags": ["rechnen"]},
  {"id": 119, "cat": "L", "label": "Proportionale RV", "q": "SuEx mit Maximum 1.000.000: Berechne die Abgabequoten für VSU = 250.000 / 1.200.000 / 3.000.000 / 8.800.000.", "a": "250.000: unter dem Maximum → **0 %** (bleibt voll beim VU). 1.200.000: 200.000/1.200.000 = **16,7 %** (83,3 % bleiben beim Erst-VU). 3.000.000: 2.000.000/3.000.000 = **66,7 %.** 8.800.000: 7.800.000/8.800.000 = **88,6 %** (nur noch 11,4 % beim VU). → Je größer das Risiko, desto mehr geht an den RV.", "tags": ["rechnen"]},
  {"id": 120, "cat": "L", "label": "Proportionale RV", "q": "Summenexzedent: Vorteile?", "a": "1) **Prozentuale Entlastung bei jedem Schadenfall** von Risiken, die den Selbstbehalt überschreiten. 2) **Haftungs-Homogenisierung des Bestands**: Die Haftung je Einzelrisiko wird auf den festgelegten Selbstbehalt begrenzt – der Bestand wird gleichmäßiger.", "tags": []},
  {"id": 121, "cat": "L", "label": "Proportionale RV", "q": "Summenexzedent: Nachteile?", "a": "1) **Änderungs-/Irrtumsrisiken werden nur bei „größeren\" Risiken transferiert** – ihre Auswirkungen auf erhebliche Portefeuille-Anteile (die vielen kleinen Risiken) verbleiben im Selbstbehalt. 2) **Hoher administrativer Aufwand:** Für **jedes einzelne Risiko** muss das Haftungs-/Prämien-/Schadenverhältnis des RV berechnet werden.", "tags": []},
  {"id": 122, "cat": "L", "label": "Proportionale RV", "q": "Quote vs. Summenexzedent: Wer transferiert Änderungs-/Irrtumsrisiken besser – und wer homogenisiert?", "a": "**Quote** transferiert Änderungs-/Irrtumsrisiken besser (RV anteilig an allem beteiligt), homogenisiert aber nicht (alle Risiken bleiben relativ gleich verteilt). **SuEx** homogenisiert den Bestand (Kappung großer Risiken), lässt aber Änderungs-/Irrtumsrisiken großteils beim VU und ist administrativ aufwändig.", "tags": []},
  {"id": 123, "cat": "M", "label": "Nicht-prop. RV", "q": "Auf welche 3 Weisen kann ein Schadenexzedent ansetzen?", "a": "1) **Einzelschadenexzedent – XL per Risk (XL/R)**, 2) **Kumulschaden-/Ereignisexzedent – XL per Event (XL/E)**, 3) **Jahresüberschadenexzedent – Stop Loss (SL).**", "tags": []},
  {"id": 124, "cat": "M", "label": "Nicht-prop. RV", "q": "Definiere Priorität, Haftung und Plafond. Wie schreibt man einen Layer?", "a": "**Priorität** = Selbst-/Eigenbehalt des Zedenten (bis hierhin zahlt das VU allein). **Haftung** = Haftstrecke des Rückversicherers. **Plafond = Priorität + Haftung** (bis hierhin zahlt der RV; alles darüber trägt das VU wieder selbst oder gibt es an einen weiteren RV/Layer ab). Schreibweise: **„Haftung xs Priorität\"**, z.B. 1 Mio. xs 1 Mio.", "tags": []},
  {"id": 125, "cat": "M", "label": "Nicht-prop. RV", "q": "Formel: RV-Leistung eines XL-Layers bei Schaden S? (Formel vor der Rechnung!)", "a": "**RV-Leistung = min( max(S − Priorität; 0); Haftung ).** Also: Was über die Priorität hinausgeht – aber höchstens die Haftstrecke. Überschreitet S den Plafond, fällt der Rest zurück an den Zedenten (**Rückfall-SB**).", "tags": ["rechnen"]},
  {"id": 126, "cat": "M", "label": "Nicht-prop. RV", "q": "XL/R mit Priorität 10.000 und Haftung 90.000 (Plafond 100.000). Wer zahlt was bei Schäden von 7.500 / 12.500 / 55.000 / 120.000?", "a": "**7.500:** unter Priorität → VU zahlt alles, RV 0. **12.500:** VU 10.000, RV 2.500. **55.000:** VU 10.000, RV 45.000. **120.000:** VU 10.000, RV 90.000 (volle Haftstrecke), **Rückfall-SB 20.000** ans VU (über Plafond). → Pro Schaden fällt die Priorität **jedes Mal neu** an!", "tags": ["rechnen"]},
  {"id": 127, "cat": "M", "label": "Nicht-prop. RV", "q": "Wie wird die Prämie bei nicht-proportionaler RV bestimmt?", "a": "**Unabhängig vom Originalbeitrag** (man kann ja nicht x % von jedem Risiko abgeben). Formen: **Fixbetrag oder Rate** (in **% des GNPI** – Gross Net Premium Income – oder als **% RoL**, Rate on Line). Dazu: **Mindest- und Vorausprämien.**", "tags": []},
  {"id": 128, "cat": "M", "label": "Nicht-prop. RV", "q": "Was sind Wiederauffüllungsprämien (Reinstatements)? (wissen, was es ist – NICHT berechnen!)", "a": "Ist die Haftstrecke eines Layers durch einen Schaden (teilweise) **verbraucht**, kann sie gegen eine **Wiederauffüllungsprämie wieder aufgefüllt** werden – damit der Schutz für weitere Ereignisse im Jahr besteht. Anzahl ist begrenzt (z.B. „2 @ 100 % p.r.t.\"). Klausur: Konzept kennen, **Berechnung nicht relevant.**", "tags": ["klausur"]},
  {"id": 129, "cat": "M", "label": "Nicht-prop. RV", "q": "Was bedeuten Jahreshöchsthaftung und Jahresselbstbehalt?", "a": "**Jahreshöchsthaftung:** Die Haftung des RV wird **vertikal (pro Ereignis) UND horizontal (über das Jahr)** begrenzt – wie lange die Haftstrecke insgesamt trägt. **Jahresselbstbehalt:** Bis zu dieser Jahresgrenze zahlt das VU selbst.", "tags": []},
  {"id": 130, "cat": "M", "label": "Nicht-prop. RV", "q": "XL/R: Vorteile und Nachteile?", "a": "**Pro:** 1) Volle Abdeckung des **zufallsindividualisierten Großschadenrisikos** (Zufallsrisiko). 2) Der RV-Fall ist oft **identisch mit dem Versicherungsfall** der Originalpolice. **Contra:** 1) **Keine Abdeckung der bestandsweit wirkenden Änderungs-/Irrtumsrisiken.** 2) Manchmal vermuteter **Moral Hazard des Zedenten** nach Überschreiten der Priorität: „Ab jetzt zahlt eh der RV\" → teurere Gutachten/Leistungen. Das VU muss Schäden weiterhin gewissenhaft bearbeiten!", "tags": []},
  {"id": 131, "cat": "M", "label": "Nicht-prop. RV", "q": "Was ist der Kumul-Schadenexzedent (XL per Event)?", "a": "Im RV-Vertrag wird definiert, was ein **rückgedecktes Schadenereignis** ist: Eine **Mehrzahl von Einzelschäden auf einzelne Risiken (Policenkumul) mit derselben Ursache** wird zu **einem Schadenereignis zusammengefasst** – darauf werden Priorität und Haftung angewendet.", "tags": []},
  {"id": 132, "cat": "M", "label": "Nicht-prop. RV", "q": "Was besagt die Zwei-Risiken-Klausel?", "a": "Sie stellt sicher, dass **nicht ein Einzelschaden auf ein einzelnes Risiko** die Haftung des RV auslösen kann – es müssen **mindestens 2 unabhängige Risiken** betroffen sein.", "tags": []},
  {"id": 133, "cat": "M", "label": "Nicht-prop. RV", "q": "Wie wird das „rückgedeckte Schadenereignis\" beim XL/E konkretisiert?", "a": "Über **räumliche und zeitliche Merkmale**: z.B. definierte **Großwetterlagen** in Sturmsparten und/oder **Stundenklauseln**, die das Ereignisausmaß zeitlich begrenzen. In der Praxis: vielfältige Ereignisdefinitionen. Berühmtes Definitionsproblem: **9/11 – ein oder zwei Ereignisse?** → muss im Vertrag so genau wie möglich geregelt sein!", "tags": []},
  {"id": 134, "cat": "M", "label": "Nicht-prop. RV", "q": "Wann möchte das VU lieber 1 zusammengefasstes Ereignis, wann lieber 2 getrennte? (Verständnisfrage!)", "a": "**1 Ereignis**, wenn beide Schäden zusammen **innerhalb der Haftstrecke** (im „blauen Bereich\") liegen → Priorität muss nur **einmal** gezahlt werden. **2 Ereignisse**, wenn die Schäden zusammen **über den Plafond hinausschießen** würden → zwar 2× Priorität, aber dafür steht **2× die volle Haftstrecke** zur Verfügung.", "tags": ["klausur"]},
  {"id": 135, "cat": "M", "label": "Nicht-prop. RV", "q": "XL/E: Vorteile und Nachteile?", "a": "**Pro:** 1) Entlastung je vertraglich definiertem Ereignisschaden auf 2+ Risiken ab Priorität bis Plafond. 2) Das Risiko der **zufälligen Anhäufung von Einzelschäden durch ein Ereignis** (Zufallsrisiko) wird auf den RV überwälzt. **Contra:** 1) **Limitierte Wiederauffüllung** der Ereignishaftung gegen Zusatzgeld → begrenzter **Frequenzschutz** für Ereignisschäden. 2) **Begrenzte Haftung pro Ereignis:** Das Risiko der Fehleinschätzung des Höchstschadens ist nur bis zum Plafond gedeckt – Reduktion nur durch höheren Plafond = höheres Entgelt.", "tags": []},
  {"id": 136, "cat": "M", "label": "Nicht-prop. RV", "q": "Wie funktioniert der Stop Loss (SL)?", "a": "Der rückgedeckte Schaden ist der **Jahresschadenaufwand** einer definierten Sparte: Alle Schäden eines Jahres werden **aufsummiert** – überschreitet die Summe eine Schwelle (Priorität), zahlt der RV bis zum Limit.", "tags": []},
  {"id": 137, "cat": "M", "label": "Nicht-prop. RV", "q": "Warum bieten Rückversicherer Stop Loss kaum an?", "a": "**Moral Hazard des VU:** Bis zur Priorität prüft das VU Schäden genau – ist sie überschritten, „winkt es alles durch\", um Kunden zufrieden zu stellen (zahlt ja der RV). Außerdem will der RV **keine zu niedrige Priorität** und setzt meist eine **Obergrenze**, oberhalb derer wieder das VU zahlt.", "tags": []},
  {"id": 138, "cat": "M", "label": "Nicht-prop. RV", "q": "SL: Wie werden Priorität/Haftung definiert, und warum gibt es keine Wiederauffüllung?", "a": "Priorität/Haftung i.d.R. in **%-Punkten der Schadenquote**; Maximalhaftung (und oft Priorität) zusätzlich mit **Absolutbetrag** limitiert. **Wiederauffüllung ist sachlich unmöglich**, weil der Jahresschadenaufwand das deckungscharakterisierende Merkmal ist (es gibt nur EIN Jahresergebnis). Anwendung: fast nur in stark schwankungsanfälligen Kumulsparten (**Sturm, Landwirtschaft, Hagel, Frost, Erdbeben**).", "tags": []},
  {"id": 139, "cat": "M", "label": "Nicht-prop. RV", "q": "SL: Vorteile und Nachteile?", "a": "**Pro:** 1) Entlastung ab der Priorität bis zum vereinbarten Limit. 2) **Passt sich automatisch der Portefeuille-Entwicklung an**, wenn Priorität & Haftung in Schadenquoten definiert sind (an der Prämienentwicklung gemessen). **Contra:** 1) **Begrenzte RV-Haftung** wegen Plafond (Fehleinschätzungsrisiko nur bis Plafond gedeckt; höherer Plafond = teurer). 2) Die Priorität liegt immer so hoch, dass sich der Zedent **netto bereits in einer spürbaren Verlustsituation** befindet.", "tags": []},
  {"id": 140, "cat": "N", "label": "Fakultative RV", "q": "Was kennzeichnet die fakultative RV?", "a": "Meist **individuelle Einzelrisiken**. Der **Zedent ist frei in der Abgabe, der RV frei in der Annahme** („Kirschenpicken\"). Es gibt Zwischenformen: **fakultativ-obligatorisch** und **obligatorisch-fakultativ.**", "tags": []},
  {"id": 141, "cat": "N", "label": "Fakultative RV", "q": "Nenne Gründe für fakultativen RV-Schutz.", "a": "**Größe** des Risikos, besondere **Struktur**, **Ein-/Ausschluss bestimmter Deckungen**, **Carve-outs**, **„politische\" Gründe** (z.B. Alleinzeichnung gewünscht, Kundenverbindung nur im Gesamtpaket erhältlich).", "tags": []},
  {"id": 142, "cat": "N", "label": "Fakultative RV", "q": "Welche Probleme/Nachteile hat die fakultative RV?", "a": "1) **Administrativ sehr aufwändig** (Zeit/Kosten) – bei vielen RV ein eigenes Cost-Center. 2) **Verhältnis Prämie/Haftung problematisch:** Ausgleich im Kollektiv kaum gegeben. 3) **Arbitragemöglichkeiten**, wenn RV „günstiger\" ist als die Originalprämie.", "tags": []},
  {"id": 143, "cat": "O", "label": "GuV-Quoten", "q": "Welche GuV-Positionen/Kennzahlen schaut man sich für die RV-Wirkung an?", "a": "Gebuchte/verdiente **Brutto- und Nettobeiträge**, **RV-Saldo (RV-Ergebnis)**, **Schadenquote** brutto vs. netto, **Kostenquote** brutto vs. netto, **Combined Ratio** brutto vs. netto, **Selbstbehaltsquote.** (Klausur: nur die **gebuchten** Beiträge anschauen; **Beitragsüberträge weglassen!**)", "tags": ["klausur"]},
  {"id": 144, "cat": "O", "label": "GuV-Quoten", "q": "Formel: Schadenquote (SQ)?", "a": "**SQ = Schadenaufwendungen / Beiträge** (jeweils brutto bzw. netto). Interpretation: Wie viel % einer Prämie gebe ich für Schäden aus? (Ggf. Schäden + Veränderung der Schadenrückstellungen im Zähler – wie im Provinzial-Beispiel.)", "tags": ["rechnen", "klausur"]},
  {"id": 145, "cat": "O", "label": "GuV-Quoten", "q": "Formel: Kostenquote (KQ)?", "a": "**KQ = Aufwendungen für den Versicherungsbetrieb / Beiträge** (brutto bzw. netto). Wie viel % der Prämie geht für Kosten drauf?", "tags": ["rechnen", "klausur"]},
  {"id": 146, "cat": "O", "label": "GuV-Quoten", "q": "Formel: Combined Ratio (CR)? Beispiel!", "a": "**CR = SQ + KQ.** Beispiel: 70 % SQ + 10 % KQ = **80 % CR.** CR < 100 % → versicherungstechnischer Gewinn; CR > 100 % → vt. Verlust.", "tags": ["rechnen", "klausur"]},
  {"id": 147, "cat": "O", "label": "GuV-Quoten", "q": "Formel: Selbstbehaltsquote? Interpretation?", "a": "**SB-Quote = Nettobeiträge / Bruttobeiträge.** „Wie viel von meinem Geld behalte ich selbst, wie viel gebe ich an den RV?\" Beispiel VHV: 93 % → 93 % der Beiträge bleiben beim VU, **7 % gehen an den RV.**", "tags": ["rechnen", "klausur"]},
  {"id": 148, "cat": "O", "label": "GuV-Quoten", "q": "VHV-Geschäftsbericht: Brutto-SQ 72 %, Brutto-KQ 21 %; Netto-SQ 71 %, Netto-KQ 22 %. Berechne die CRs und interpretiere.", "a": "CR brutto = 72 + 21 = **93 %**, CR netto = 71 + 22 = **93 %.** → Brutto wie netto profitabel; die RV hat das Ergebnis kaum verändert (SQ leicht besser, KQ leicht schlechter durch die Abgabe). SB-Quote 93 %: nur 7 % der Beiträge gehen an den RV.", "tags": ["rechnen", "klausur"]},
  {"id": 149, "cat": "O", "label": "GuV-Quoten", "q": "Provinzial (Flutjahr 2021): Bruttoschäden + Rückstellungsveränderung = 2.194.800 + 1.125.785; Bruttobeiträge 2.898.128; Bruttokosten 747.310. Netto: SQ 90,6 %, KQ 26 %. Berechne brutto und interpretiere.", "a": "Brutto-SQ = 3.320.585 / 2.898.128 = **114,6 %**; Brutto-KQ = 747.310 / 2.898.128 = **25,8 %**; **CR brutto = 140,4 %** vs. **CR netto = 116,6 %.** SB-Quote = 2.517.806 / 2.898.128 = **86,9 %.** Interpretation: Ahrtal-Flutjahr 2021 – mehr Schäden als Beitragseinnahmen. **Netto deutlich besser als brutto → die RV hat massiv geholfen** (zugunsten des Versicherers gelaufen).", "tags": ["rechnen", "klausur"]},
  {"id": 150, "cat": "O", "label": "GuV-Quoten", "q": "Wie sieht das Verhältnis Brutto-SQ vs. Netto-SQ in einem NORMALEN Jahr aus – und warum?", "a": "In einem normalen Jahr ist **Netto-SQ > Brutto-SQ**: Wir zahlen mehr (Prämie) an den RV, als er uns (Leistung) zahlt. Nur in Schadenjahren dreht sich das Verhältnis (Netto < Brutto). → In der Klausur immer prüfen: **Lief das Jahr zugunsten des Versicherers oder des RV?**", "tags": ["klausur"]},
  {"id": 151, "cat": "O", "label": "GuV-Quoten", "q": "Warum ist die Kostenquote brutto ≈ netto?", "a": "Weil die **Kosten relativ konstant bleiben** – egal ob das Jahr glücklich oder unglücklich läuft (es wird ja kein neues Geschäftsgebiet erschlossen o.ä.). Die RV verändert primär die Schadenseite.", "tags": ["klausur"]},
  {"id": 152, "cat": "O", "label": "GuV-Quoten", "q": "CR liegt über 100 % – was kann der Vorstand tun, um aus dem Minus ein Plus zu machen?", "a": "**Schwankungsrückstellungen auflösen** (sofern die Kriterien erfüllt sind) – das geglättete Ergebnis stabilisiert die GuV gegenüber Investoren.", "tags": ["klausur"]},
  {"id": 153, "cat": "O", "label": "GuV-Quoten", "q": "ERGO: Bruttoschäden 3.363.933, Bruttobeiträge 5.082.006, Brutto-KQ 29,3 %; netto SQ 66,9 %, KQ 30,1 %. Berechne Brutto-SQ und beide CRs – normales oder Schadenjahr? (Kontrollbeispiel)", "a": "Brutto-SQ = 3.363.933 / 5.082.006 = **66,2 %.** CR brutto = 66,2 + 29,3 = **95,5 %**; CR netto = 66,9 + 30,1 = **97 %.** SB-Quote 95,1 %. **Netto schlechter als brutto → normales Jahr**, die RV hat netto Geld gekostet (erwartbar – sie ist eine Versicherung, kein Gewinnbringer).", "tags": ["rechnen", "klausur"]},
  {"id": 154, "cat": "P", "label": "NatCat", "q": "Was macht ein NatCat-Modell und was bedeutet eine Wiederkehrperiode von 1 %?", "a": "Es **modelliert die Wahrscheinlichkeit von Naturgefahren**. Angabe in **Wiederkehrperioden**: 1 % Wahrscheinlichkeit = das Ereignis tritt **statistisch alle 100 Jahre** ein (= „100-jährliches Ereignis\"). Achtung: Das ist eine Wahrscheinlichkeitsaussage, kein Fahrplan – es kann auch zweimal in zehn Jahren kommen.", "tags": []},
  {"id": 155, "cat": "P", "label": "NatCat", "q": "Nenne die Hauptnaturgefahren in Deutschland und weitere Elementargefahren (eher woanders auf der Welt).", "a": "**Deutschland:** Sturm, Hagel, Überschwemmung/Hochwasser/Starkregen, Erdbeben. **Weitere (eher global):** Erdrutsch, Erdsenkung, Lawinen, Vulkanausbruch, Schneedruck.", "tags": []},
  {"id": 156, "cat": "P", "label": "NatCat", "q": "Welche Großgefahren jenseits der klassischen Naturgefahren könnte man sich noch vorstellen? (Diskussionsfrage des Dozenten)", "a": "**Man-made-Großgefahren: Terror, Krieg, Cyber, Pandemie.** Sie haben NatCat-ähnlichen Charakter (selten, aber extrem teuer, hohes Kumulpotential), sind aber schwerer modellierbar.", "tags": ["klausur"]},
  {"id": 157, "cat": "P", "label": "NatCat", "q": "Vorteile und Grenzen von NatCat-Modellen?", "a": "**+** Klimawandel, **Wertekonzentrationen** und **Simulationen** (auch von Ereignissen, die es real noch nie gab) lassen sich gut darstellen. **−** Unsicherheit: Modelle basieren nur auf **historischen Daten + Expertenvorhersagen** → **keine Garantie**. Und: **0,5 % ist nicht 0** – es können auch teurere Ereignisse eintreten als modelliert.", "tags": []},
  {"id": 158, "cat": "Q", "label": "RV-Politik", "q": "RV-Politik aus Zedenten-Sicht: Welche Kriterien bestimmen, ob/wie viel RV ein VU kauft?", "a": "Merke in 4 Gruppen: **(1) Wer bin ich?** Kapitalkraft (EK, auch SchwaRü!), Unternehmensform, Sitz & Bilanzierungsstandard, individuelle Risikoneigung, Erwartungen der Stakeholder. **(2) Was zeichne ich?** Portefeuillemix/Sparten (+ deren Korrelation), Geschäftsgebiete, Arten der Risiken (+ Homogenität). **(3) Was kann/muss ich?** Eigene Zeichnungskapazität, „Zwang\" zur Übernahme gewisser Risiken. **(4) Wie läuft's?** Verlauf des rückzuversichernden Geschäfts, Service-/Beratungsbedarf.", "tags": []},
  {"id": 159, "cat": "Q", "label": "RV-Politik", "q": "RV-Politik aus Sicht des Zessionärs (RV): Nach welchen Kriterien entscheidet er, RV-Schutz zu GEBEN?", "a": "Kapitalkraft & **Risikokapital**, Sitz & Bilanzierungsstandard, **Know-how**, Kostenstruktur, **Kumulpotential**, Verfügbarkeit/Abhängigkeit von **Retrozession**, Managementvorgaben (z. B. allgemeine Ausschlüsse, Wording-Vorgaben).", "tags": []},
  {"id": 160, "cat": "Q", "label": "RV-Politik", "q": "Nach welchen Kriterien wählt ein VU seine RV-Partner aus?", "a": "**Langfristig vs. opportunistisch**, **Security/Rating**, **Streuung** (Abhängigkeit von einem RV vermeiden), Sitzland/Firmenstruktur/Eigentümer, **Solvency-II-Äquivalenz**, persönlicher Kontakt & **Vertrauen**, **Verlässlichkeit in „schwierigen\" Situationen**, Service-/Beratungsqualität, operative Exzellenz (Accounting, Claims), **Reziprozität** (Gegenseitigkeit im Geschäft).", "tags": []},
  {"id": 161, "cat": "Q", "label": "RV-Politik", "q": "Was ist eine Schiedsvereinbarung im RV-Vertrag – und worin liegt der Unterschied zur Rechtsanwendung beim Erstversicherer?", "a": "Beim E-VU landet Streit meist **vor Gericht**. Im RV-Vertrag wird die **allgemeine Gerichtsbarkeit ausgesetzt** und durch ein **Schiedsgerichtsverfahren** ersetzt.", "tags": []},
  {"id": 162, "cat": "Q", "label": "RV-Politik", "q": "Vier Vorteile des Schiedsverfahrens in der RV?", "a": "(1) Man redet auf **Fachebene** (Profis unter sich), (2) **Privatsphäre** – die Öffentlichkeit bekommt nichts mit, (3) **schneller** als vor Gericht, Lösung ist **bindend**, (4) man **verscherzt es sich nicht** mit seinen Rückversicherern (Geschäftsbeziehung bleibt intakt).", "tags": []},
  {"id": 163, "cat": "Q", "label": "RV-Politik", "q": "Welche 5 Aufgaben/Funktionen hat ein RV-Broker (RV-Makler)?", "a": "**(1) Beratung** (z. B. RV-Strukturen), **(2) Unterstützung/Service** (aktuarielle Berechnungen, NatCat-Modeling), **(3) Platzierung** (weltweites Netzwerk, Zugang zu bestimmten Märkten), **(4) Administration** (Wording, Claims), **(5) Informationen** (Marktentwicklungen, Peer-Vergleich).", "tags": []},
  {"id": 164, "cat": "Q", "label": "RV-Politik", "q": "In wessen Interesse ist der RV-Broker tätig und wie wird er vergütet?", "a": "Grundsätzlich **im Interesse des Zedenten (VU)**. Vergütung: i. d. R. **Provision (= Courtage/Brokerage)**, seltener eine **Fee**.", "tags": []},
  {"id": 165, "cat": "R", "label": "ART & Cat Bonds", "q": "Warum gibt es den Alternativen Risikotransfer (ART)?", "a": "Weil klassische (Rück-)Versicherung für **manche Risiken, Zeiträume oder Preisvorstellungen nicht die beste Lösung** ist. ART verschiebt Risiken ganz/teilweise an den **Kapitalmarkt** oder nutzt andere Strukturen (**Captives, Cat Bonds, Contingent Capital**), um **Kapazität, Flexibilität und Planungssicherheit** zu gewinnen.", "tags": ["klausur"]},
  {"id": 166, "cat": "R", "label": "ART & Cat Bonds", "q": "Was ist die Motivation für VU & RV, alternatives Kapital zu nutzen?", "a": "**Zusätzliche Kapazität**, **Diversifikation** der RV-Programme, **weniger Abhängigkeit** von einzelnen Marktteilnehmern; bei Kapitalmarktlösungen zudem **Wegfall/Reduktion des Kreditrisikos** (Kapital ist hinterlegt). Für E-VU außerdem: **schwer versicherbare Risiken** doch decken, **Prämienvolatilität senken**. Für RV: Instrumente, die zu langfristigen Verpflichtungen passen.", "tags": ["klausur"]},
  {"id": 167, "cat": "R", "label": "ART & Cat Bonds", "q": "Welche alternativen Kapitalgeber gibt es – und warum geben sie Geld?", "a": "Vor allem **institutionelle Investoren**: Pensionskassen, Investmentfonds, Banken. Warum: Versicherungsrisiken sind für sie eine **eigene Anlageklasse** mit Erträgen, die sich von Aktien/Anleihen unterscheiden → **Diversifikation** + Risiko-Rendite-Beimischung.", "tags": ["klausur"]},
  {"id": 168, "cat": "R", "label": "ART & Cat Bonds", "q": "Warum möchten Investoren in Versicherungsrisiken investieren?", "a": "Sie erhalten (z. B. bei Cat Bonds) eine **Prämie** für ein **klar definiertes Risiko** – bei meist **attraktiver Rendite** und **geringer Korrelation** zu anderen Märkten.", "tags": ["klausur"]},
  {"id": 169, "cat": "R", "label": "ART & Cat Bonds", "q": "Warum gründen diese Investoren nicht einfach eine eigene Versicherung?", "a": "Viel zu aufwendig: **Lizenzierung, Regulierung, Kapitalunterlegung, Schadenmanagement und operatives Know-how** wären nötig. Über ART tragen sie nur das Risiko – ohne den Apparat.", "tags": ["klausur"]},
  {"id": 170, "cat": "R", "label": "ART & Cat Bonds", "q": "ART hat drei „alternative\" Dimensionen. Nenne sie mit Beispielen.", "a": "**(1) Alternative RISIKEN** (nicht traditionell (rück)versicherbar): Kapitalmarktentwicklungen, unternehmerische Risiken, Markenimage. **(2) Alternative STRUKTUREN** (kein (R)V-Vertrag): Wetterderivate, Cat Bonds. **(3) Alternative MÄRKTE** (keine (R)V-Gesellschaften): Kapitalmarkt, Banken, Pensionsfonds, Family Offices.", "tags": ["klausur"]},
  {"id": 171, "cat": "R", "label": "ART & Cat Bonds", "q": "Erkläre die Grundstruktur eines Cat Bonds (4 Beteiligte und die Zahlungsströme).", "a": "**Sponsor** (VU/RV) schließt mit einer Zweckgesellschaft (**SPV**) einen RV-Vertrag und zahlt die **Reinsurance Premium**. Das SPV emittiert Anleihen an **Investoren**, die die **Note Proceeds** (Kapital) einzahlen. Das Kapital liegt in einem **Collateral Account** (vorab hinterlegt!). Kein Trigger-Ereignis → Investoren bekommen Kapital + Kupon zurück. Trigger-Ereignis → Kapital fließt (teilweise/ganz) an den Sponsor.", "tags": ["klausur"]},
  {"id": 172, "cat": "R", "label": "ART & Cat Bonds", "q": "Vier Vorteile eines Cat Bonds für den Sponsor?", "a": "**(1) Zusätzliche Risikokapazität** außerhalb des klassischen RV-Markts, **(2) sofort verfügbare Sicherheit** – Kapital ist bei Emission hinterlegt → **geringes Ausfall-/Kreditrisiko**, **(3) flexible Strukturierung** (Laufzeit, Trigger, Deckungshöhe individuell), **(4) Diversifikation der Risikoträger** – keine Abhängigkeit nur vom RV.", "tags": ["klausur"]},
  {"id": 173, "cat": "R", "label": "ART & Cat Bonds", "q": "Vorteil von Cat Bonds für Investoren?", "a": "**Eigene Risikoprämie** mit oft **geringer/keiner Korrelation** zu Aktien/Anleihen → **Diversifikation des Depots** + Erschließung **zusätzlicher Renditequellen**.", "tags": ["klausur"]},
  {"id": 174, "cat": "R", "label": "ART & Cat Bonds", "q": "Vier Nachteile von Cat Bonds für Investoren?", "a": "**(1) Verlustrisiko bei Trigger** (Teil-/Totalverlust des Kapitals möglich), **(2) Modell- & Basisrisiko** (Auszahlung hängt am Trigger, der vom echten Schaden abweichen kann), **(3) Komplexität** (strukturierte Produkte, schwerer verständlich als klassische Anleihen), **(4) konzentriertes Katastrophenrisiko** (selten, aber schwer).", "tags": ["klausur"]},
  {"id": 175, "cat": "R", "label": "ART & Cat Bonds", "q": "Welche drei Trigger-Arten (Auslösemechanismen) gibt es bei Cat Bonds?", "a": "**(1) Indemnity** – orientiert sich am Originalschaden des Zedenten. **(2) Industry (Loss) Index** – orientiert sich am Marktschaden des Events. **(3) Parametric** – physikalisch messbares, objektives Kriterium (z. B. Windgeschwindigkeit).", "tags": ["klausur"]},
  {"id": 176, "cat": "R", "label": "ART & Cat Bonds", "q": "Indemnity-Trigger: je ein Vor- und Nachteil?", "a": "**+** Regulatorische **Akzeptanz nach Solvency II** (deckt den echten Schaden → echter Risikotransfer). **−** **Moral Hazard** (VU könnte den Schaden „hochspielen\") & **lange Abwicklungsdauer** (erst muss der Originalschaden feststehen).", "tags": ["klausur"]},
  {"id": 177, "cat": "R", "label": "ART & Cat Bonds", "q": "Industry-Loss-Index-Trigger: je ein Vor- und Nachteil?", "a": "**+ Transparenz** (neutraler Marktschaden-Index). **− Basisrisiko**: Sponsor kann viel verlieren, ohne dass der Trigger auslöst – oder wenig verlieren und trotzdem gibt's eine Auszahlung.", "tags": ["klausur"]},
  {"id": 178, "cat": "R", "label": "ART & Cat Bonds", "q": "Parametric-Trigger: je ein Vor- und Nachteil?", "a": "**+ Abwicklungsgeschwindigkeit** (Messwert liegt sofort vor, z. B. Windstärke). **− Basisrisiko**: ein starkes Ereignis passt nicht immer zum tatsächlichen Schaden des Sponsors.", "tags": ["klausur"]},
  {"id": 179, "cat": "R", "label": "ART & Cat Bonds", "q": "Was bedeutet „Basisrisiko\" bei Cat Bonds?", "a": "Die Gefahr, dass **Trigger-Auszahlung und tatsächlicher Schaden des Sponsors auseinanderfallen** – in beide Richtungen: großer Schaden ohne Auszahlung oder Auszahlung ohne entsprechenden Schaden. Betrifft v. a. Index- und Parametric-Trigger.", "tags": ["klausur"]},
  {"id": 192, "cat": "Z", "label": "Roter Faden", "q": "Der rote Faden des Kurses in einem Satz?", "a": "**Risiken identifizieren → bewerten (σ, VaR, TVaR) → steuern** (vermeiden/vermindern/überwälzen/selbst tragen – zentrales Instrument: **Rückversicherung**, proportional & nicht-proportional, ergänzt um **ART/Cat Bonds**) → **überwachen** (Solvency II, GuV-Quoten) – alles im Rahmen der **Risikostrategie**.", "tags": []}
];

// Block S — die große Klausuraufgabe als geführte Rechenkette (Original-Karten 180–191)
const RISK_EXAM = [
  {"id": 1, "q": "Beschreibe die Struktur des RV-Programms aus der Übungsaufgabe: Welche Verträge greifen in welcher Reihenfolge? (Setup – erst diese Karte sicher können!)", "a": "**Stufe 1 – vorweggehende proportionale RV** (pro Sparte): Kasko **Quote 25 %** Abgabe, Verbundene Gebäude (VGV) **Quote 40 %** Abgabe, Industrie **Summenexzedent** (Maximum/Eigenbehalt **1.000.000**, 9 Maxima), Photovoltaik (Technische Vers.): **keine** prop. RV. **Stufe 2 – Kumul-XL (pro Ereignis)** auf den **Netto**-Eigenbehalt: Priorität **500.000**; Layer 1: **0,5 Mio xs 0,5 Mio**; Layer 2: **1 Mio xs 1 Mio**; Layer 3: **3 Mio xs 2 Mio**. **Stufe 3 – abschließender Stop Loss.** Merksatz: **Erst proportional, dann XL aufs Netto, zuletzt SL.**", "tags": ["klausur"]},
  {"id": 2, "q": "Die Ausgangsdaten der Aufgabe (Ereignis „Heidenheim\")? (Daten-Referenz)", "a": "**Kasko:** 2.000 Risiken, Beitrag 500.000, Ereignisschaden 400.000. **VGV:** 5.000 Risiken, Beitrag 750.000, Schaden 1.000.000. **Photovoltaik (TV):** 250 Risiken, Beitrag 45.000, Schaden 15.000. **Industrie (VSU / Beitrag / Schaden):** A 250.000/3.500/68.000 · B 750.000/7.500/0 · C 1.200.000/13.000/0 · D 3.000.000/22.000/1.500.000 · E 4.250.000/25.000/250.000 · F 6.750.000/32.500/0 · G 8.800.000/38.000/600.000.", "tags": []},
  {"id": 3, "q": "Schritt 1a: Berechne die RV-Beiträge der beiden Quoten (Kasko 25 %, VGV 40 %).", "a": "Quote → RV bekommt den Abgabesatz **vom Beitrag**: Kasko: 25 % × 500.000 = **125.000**. VGV: 40 % × 750.000 = **300.000**. (Photovoltaik: keine prop. RV → kein RV-Beitrag.)", "tags": ["rechnen"]},
  {"id": 4, "q": "Schritt 1b: Leite für die Industrie-Risiken A–G die SuEx-Abgabequoten her. Formel zuerst!", "a": "**q = (VSU − Eigenbehalt) / VSU**, hier Eigenbehalt = 1.000.000; VSU ≤ 1 Mio → q = 0. **A (250.000): 0 %** · **B (750.000): 0 %** · **C (1,2 Mio): 200.000/1,2 Mio = 16,67 %** · **D (3 Mio): 2 Mio/3 Mio = 66,67 %** · **E (4,25 Mio): 3,25/4,25 = 76,47 %** · **F (6,75 Mio): 5,75/6,75 = 85,19 %** · **G (8,8 Mio): 7,8/8,8 = 88,64 %**.", "tags": ["rechnen"]},
  {"id": 5, "q": "Schritt 1c: Berechne den RV-Beitrag des Summenexzedenten (Quoten aus Karte 183 × Beiträge).", "a": "Pro Risiko q × Beitrag: C: 16,67 % × 13.000 = **2.166,67** · D: 66,67 % × 22.000 = **14.666,67** · E: 76,47 % × 25.000 = **19.117,65** · F: 85,19 % × 32.500 = **27.685,19** · G: 88,64 % × 38.000 = **33.681,82**. **Summe ≈ 97.318.** (A & B: q = 0 → nichts.) Logik: Beim SuEx hat **jedes Risiko seine eigene Quote** – deshalb risikoweise rechnen!", "tags": ["rechnen"]},
  {"id": 6, "q": "Schritt 2a: Nettoschäden aus dem Ereignis für Kasko, VGV und Photovoltaik?", "a": "Netto = Selbstbehaltsquote × Schaden: **Kasko: 75 % × 400.000 = 300.000** · **VGV: 60 % × 1.000.000 = 600.000** · **Photovoltaik: keine prop. RV → brutto = netto = 15.000.**", "tags": ["rechnen"]},
  {"id": 7, "q": "Schritt 2b: Nettoschäden der Industrie-Risiken (per Risk, mit den q aus Karte 183)?", "a": "Netto = (1 − q) × Schaden: **A:** q = 0 → **68.000** · **D:** 33,33 % × 1.500.000 = **500.000** (RV trägt 1.000.000) · **E:** 23,53 % × 250.000 = **58.824** (RV 191.176) · **G:** 11,36 % × 600.000 = **68.182** (RV 531.818). **Industrie netto gesamt ≈ 695.005** (brutto 2.418.000, RV-Anteil ≈ 1.722.995).", "tags": ["rechnen"]},
  {"id": 8, "q": "Schritt 3: Gesamt-Nettoschaden des Ereignisses und Leistung der np-RV (Kumul-XL, Priorität 500.000)?", "a": "Netto gesamt = 300.000 + 600.000 + 15.000 + 695.005 = **1.610.005**. XL-Leistung = Nettoschaden − Priorität = 1.610.005 − 500.000 = **1.110.005**. (Die ersten 500.000 trägt das VU selbst.)", "tags": ["rechnen"]},
  {"id": 9, "q": "Schritt 4: Welche Layer sind in welcher Höhe betroffen?", "a": "**Layer 1 (0,5 xs 0,5): voll ausgeschöpft = 500.000.** **Layer 2 (1 xs 1): mit 610.005 von 1.000.000 = 61 % ausgeschöpft.** **Layer 3 (3 xs 2): unberührt.** Kontrolle: 500.000 + 610.005 = 1.110.005 ✓", "tags": ["rechnen"]},
  {"id": 10, "q": "Wie würde man konzeptionell die Wiederauffüllungsprämie für Layer 2 berechnen (pro rata, RoL 8 %)? (Konzept – laut Dozent NICHT klausurrelevant)", "a": "Ursprüngliche Layer-Prämie = RoL × Haftung = 8 % × 1.000.000 = 80.000. WA-Prämie pro rata zur Ausschöpfung: **61 % × 80.000 = 48.800**. → Nur das Prinzip verstehen (Ausschöpfung × Prämie), Rechnung kommt nicht dran.", "tags": []},
  {"id": 11, "q": "Schritt 6: Warum steht am Ende des Programms noch ein Stop Loss – welche Lücke schließt er?", "a": "Der XL schützt pro **Ereignis** – aber die **Priorität (500.000) fällt bei JEDEM Ereignis neu an** und Wiederauffüllungen sind **limitiert und teuer**. Bei vielen Ereignissen (Frequenz!) summieren sich die Selbstbehalte. Der **SL deckelt die Netto-Gesamtschadenquote des Jahres** → Schutz gegen Frequenz + finale Ergebnisglättung.", "tags": ["klausur"]},
  {"id": 12, "q": "Die 4 typischen Fehlerquellen in dieser Klausuraufgabe? (Fehlerquellen-Check)", "a": "**(1)** Beim SuEx eine Einheitsquote nehmen – falsch, **jedes Risiko hat eigene q**. **(2)** Den XL auf den **Brutto**schaden rechnen – falsch, er greift auf den **Netto**-Eigenbehalt nach prop. RV. **(3)** Photovoltaik vergessen – sie hat **keine prop. RV**, läuft aber voll in den Nettoschaden. **(4)** Risiken mit VSU ≤ 1 Mio (A, B) in den SuEx einbeziehen – die bleiben **komplett im Selbstbehalt**.", "tags": ["achtung"]}
];
